        System.out.println("sql combo--> SELECT\n`i_suministro`.`Id`\n, UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacioncomercial.`Nbre`='NO APLICA','', i_presentacioncomercial.`Nbre`))) Nbre\n, `i_presentacioncomercial`.`valorNumerico`, i_concentracion.`NInvima` \nFROM\n     `i_suministro`\n    INNER JOIN  `i_principioactivo` \n        ON (`i_suministro`.`IdPrincipioActivo` = `i_principioactivo`.`Id`)\n    INNER JOIN  `i_tipoproducto` \n        ON (`i_suministro`.`IdTipoProducto` = `i_tipoproducto`.`Id`)\n    INNER JOIN  `i_concentracion` \n        ON (`i_suministro`.`IdConcentracion` = `i_concentracion`.`Id`)\n          INNER JOIN  `i_unidadmedida` \n        ON (`i_suministro`.`IdUnidadMedida` = `i_unidadmedida`.`Id`)\n    INNER JOIN  `i_presentacioncomercial` \n        ON (`i_suministro`.`IdPresentacionComercial` = `i_presentacioncomercial`.`Id`)\n    INNER JOIN  `i_presentacionfarmaceutica` \n        ON (`i_suministro`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica`.`Id`)\n    INNER JOIN  `i_suministroxbodega` \n        ON (`i_suministroxbodega`.`IdSuministro` = `i_suministro`.`Id`)\n    INNER JOIN  `i_bodegas` \n        ON (`i_suministroxbodega`.`IdBodega` = `i_bodegas`.`Id`)\nWHERE (`i_tipoproducto`.`esSolucion` =1\n    AND `i_bodegas`.`EsUrg` =1\n  --   AND `i_suministro`.`EstaActivo` =1\n AND `i_suministro`.`ActivoHc` =1\n)\nORDER BY `i_suministro`.`Nbre` ASC");
        List<Object[]> list = this.jdbcTemplate.query("SELECT\n`i_suministro`.`Id`\n, UPPER(CONCAT(IF(i_principioactivo.`Nbre`='NO APLICA',i_suministro.`Nbre`,i_principioactivo.`Nbre`),' ', IF(i_concentracion.`Nbre`='NO APLICA' OR i_concentracion.`Nbre`='-','',i_concentracion.`Nbre`) ,' ', IF(i_presentacioncomercial.`Nbre`='NO APLICA','', i_presentacioncomercial.`Nbre`))) Nbre\n, `i_presentacioncomercial`.`valorNumerico`, i_concentracion.`NInvima` \nFROM\n     `i_suministro`\n    INNER JOIN  `i_principioactivo` \n        ON (`i_suministro`.`IdPrincipioActivo` = `i_principioactivo`.`Id`)\n    INNER JOIN  `i_tipoproducto` \n        ON (`i_suministro`.`IdTipoProducto` = `i_tipoproducto`.`Id`)\n    INNER JOIN  `i_concentracion` \n        ON (`i_suministro`.`IdConcentracion` = `i_concentracion`.`Id`)\n          INNER JOIN  `i_unidadmedida` \n        ON (`i_suministro`.`IdUnidadMedida` = `i_unidadmedida`.`Id`)\n    INNER JOIN  `i_presentacioncomercial` \n        ON (`i_suministro`.`IdPresentacionComercial` = `i_presentacioncomercial`.`Id`)\n    INNER JOIN  `i_presentacionfarmaceutica` \n        ON (`i_suministro`.`IdPresentacionFarmaceutica` = `i_presentacionfarmaceutica`.`Id`)\n    INNER JOIN  `i_suministroxbodega` \n        ON (`i_suministroxbodega`.`IdSuministro` = `i_suministro`.`Id`)\n    INNER JOIN  `i_bodegas` \n        ON (`i_suministroxbodega`.`IdBodega` = `i_bodegas`.`Id`)\nWHERE (`i_tipoproducto`.`esSolucion` =1\n    AND `i_bodegas`.`EsUrg` =1\n  --   AND `i_suministro`.`EstaActivo` =1\n AND `i_suministro`.`ActivoHc` =1\n)\nORDER BY `i_suministro`.`Nbre` ASC", mapper);
